create table workspaces (id text primary key, created_at timestamptz not null, updated_at timestamptz not null, optional_label text, monitoring_enabled boolean not null default true, refresh_interval_minutes integer not null default 5);
create table sessions (id text primary key, workspace_id text not null references workspaces(id), created_at timestamptz not null, last_seen_at timestamptz not null, last_activity_at timestamptz, last_heartbeat_at timestamptz, user_agent_approx text, ip_hash text, country text, region text, city text, timezone text, asn text, organization text, notification_permission text, api_activity_count integer not null default 0, page_load_count integer not null default 0);
create table usage_events (id text primary key, workspace_id text references workspaces(id), session_id text references sessions(id), event_type text not null, metadata_json text, created_at timestamptz not null);
create table flights (id text primary key, workspace_id text not null references workspaces(id), display_flight_number text not null, normalized_acid text not null, origin text not null, destination text not null, etd_utc timestamptz not null, scheduled_departure_utc timestamptz, scheduled_arrival_utc timestamptz, operational_day_key text not null, active boolean not null default true, created_at timestamptz not null, updated_at timestamptz not null);
create table source_airport_snapshots (id text primary key, airport text not null, fetched_at timestamptz not null, success boolean not null, record_count integer not null default 0, normalized_records_json text, error_message text);
create table admin_events (id text primary key, event_type text not null, message text not null, created_at timestamptz not null);
create table edct_flight_states (id text primary key, workspace_id text not null references workspaces(id), normalized_acid text not null, origin text not null, destination text not null, operational_day_key text not null, flight_id text references flights(id), current_edct_utc timestamptz, previous_edct_utc timestamptz, last_change text, last_seen_at timestamptz, last_source_fetch_at timestamptz, source_record_json text, unique (workspace_id, normalized_acid, origin, destination, operational_day_key));
create table edct_events (id text primary key, workspace_id text not null references workspaces(id), flight_id text not null references flights(id), flight_signature text not null, event_type text not null, previous_edct_utc timestamptz, new_edct_utc timestamptz, delay_minutes integer, source_airport text not null, source_fetch_at timestamptz not null, message text not null, created_at timestamptz not null, unique (workspace_id, flight_signature, event_type, previous_edct_utc, new_edct_utc));
create table notification_events (id text primary key, workspace_id text not null references workspaces(id), edct_event_id text not null unique references edct_events(id), title text not null, body text not null, created_at timestamptz not null);
create table notification_deliveries (id text primary key, notification_event_id text not null references notification_events(id), session_id text not null references sessions(id), delivery_state text not null, attempted_at timestamptz not null, delivered_at timestamptz);
